'use client';

import React, { useMemo, useState } from 'react';
import { Layout, Menu, Input, ConfigProvider, Avatar } from 'antd';
import { SearchOutlined } from '@ant-design/icons';
import { useRouter, usePathname } from 'next/navigation';
import Link from 'next/link';
import menuData from '@/constants/data/menu-config.json';
import { filterMenuByPermission } from '@/lib/menu-utils';
import { NavItem } from '@/types/nav';
import { getIcon } from '@/lib/icon-loader';
import type { MenuProps } from 'antd';
import { useTranslation } from 'react-i18next';
import { useTheme } from '@/lib/ThemeProvider';
import { usePermission } from '@/lib/PermissionProvider';
import { getUserId } from '@/lib/auth-utils';
import { getUserByIdApi } from '@/services/userService';
import { FormModal, UserDataType } from '@/app/(pages)/(administrator)/users/FormModal';

const { Sider } = Layout;
type MenuItem = Required<MenuProps>['items'][number];

export default function Navbar() {
    const { t } = useTranslation();
    const { primaryColor, isDarkMode } = useTheme();
    const { permissions: userPermissions, features, tenantName, tenantCode, userName, isHostTenant } = usePermission();

    const router = useRouter();
    const pathname = usePathname();
    const [openKeys, setOpenKeys] = useState<string[]>([]);
    const [searchValue, setSearchValue] = useState('');
    const [mounted, setMounted] = useState(false);

    // Mở popup cập nhật Profile
    const [profileModalOpen, setProfileModalOpen] = useState(false);
    const [currentUserData, setCurrentUserData] = useState<UserDataType | null>(null);

    React.useEffect(() => {
        setMounted(true);
    }, []);

    const authorizedMenu = useMemo(() => {
        return filterMenuByPermission(menuData as NavItem[], userPermissions, features, isHostTenant);
    }, [userPermissions, features, isHostTenant]);

    // 2. Hàm đệ quy chuyển đổi sang MenuItem (Giữ nguyên logic của bạn)
    const mapItems = (menuList: NavItem[]): MenuItem[] => {
        return menuList.map((item) => ({
            key: item.path === "#" ? `sub-${item.title}` : item.path,
            label: item.path === "#" ? t(item.titleKey || item.title) : (
                <Link href={item.path} prefetch={true}>
                    {t(item.titleKey || item.title)}
                </Link>
            ),
            icon: getIcon(item.icon),
            children: item.children ? mapItems(item.children) : undefined,
        }));
    };
    // Sử dụng useMemo để tối ưu hiệu năng khi lọc
    const filteredMenuItems = useMemo(() => {
        if (!searchValue) return authorizedMenu;
        return searchMenu(authorizedMenu, searchValue);
    }, [searchValue, authorizedMenu, t]);

    // Chuyển đổi sang định dạng AntD
    const items = useMemo(() => mapItems(filteredMenuItems), [filteredMenuItems, t]);


    // 3. Xử lý Accordion và Navigation
    const onOpenChange: MenuProps['onOpenChange'] = (keys) => {
        // 1. Tìm key cuối cùng người dùng vừa nhấn
        const latestOpenKey = keys.find((key) => openKeys.indexOf(key) === -1);

        // 2. Danh sách các key cấp cao nhất (Root) - Bạn có thể lấy từ authorizedMenu
        // Ví dụ: ['sub-Trang chủ', 'sub-Quản lý dữ liệu chủ', '/orders']
        const rootKeys = authorizedMenu.map((item: NavItem) =>
            item.path === "#" ? `sub-${item.title}` : item.path
        );

        if (latestOpenKey && rootKeys.indexOf(latestOpenKey) === -1) {
            // Nếu đang mở menu cấp con (cấp 2, cấp 3...), giữ nguyên mảng keys của AntD
            setOpenKeys(keys);
        } else {
            // Nếu mở một menu cha (cấp 1) mới, thì mới thực hiện Accordion (đóng cái cũ)
            setOpenKeys(latestOpenKey ? [latestOpenKey] : []);
        }
    };

    const onClick: MenuProps['onClick'] = (e) => {
        console.log("Key được click:", e.key);

        if (!e.key.startsWith('sub-')) {
            // router.push already handled natively by Next.js <Link> wrapper inside the label
            // but left here as fallback if needed, <Link> takes priority for prefetching
            router.push(e.key);
        }
    };

    const handleProfileClick = async () => {
        try {
            const userId = getUserId();
            if (!userId) return;
            const data = await getUserByIdApi(userId);
            setCurrentUserData(data);
            setProfileModalOpen(true);
        } catch (error) {
            console.error("Lỗi khi tải thông tin user", error);
        }
    };

    // Hàm lọc menu đệ quy theo từ khóa tìm kiếm
    function searchMenu(menuList: NavItem[], term: string): NavItem[] {
        return menuList
            .map((item): NavItem | null => {
                const translatedTitle = t(item.titleKey || item.title);

                // Nếu item con có chứa từ khóa
                const filteredChildren = item.children ? searchMenu(item.children, term) : undefined;

                // Điều kiện khớp: Tên menu chứa từ khóa HOẶC có con khớp từ khóa
                const isMatch = translatedTitle.toLowerCase().includes(term.toLowerCase()) ||
                    item.title.toLowerCase().includes(term.toLowerCase());

                if (isMatch || (filteredChildren && filteredChildren.length > 0)) {
                    return { ...item, children: filteredChildren };
                }
                return null;
            })
            .filter((item): item is NavItem => item !== null);
    }
    // 3. TỰ ĐỘNG BUNG: Tính toán tất cả keys cần mở khi đang search
    const searchOpenKeys = useMemo(() => {
        return searchValue ? getAllKeys(items) : [];
    }, [searchValue, items]);

    //Tránh lỗi Hydration mismatch khi i18n thay đổi ngôn ngữ ở Client
    // QUAN TRỌNG: Early return phải nằm SAU TẤT CẢ các Hook
    if (!mounted) {
        return <Sider width={260} theme="light" className="h-screen fixed left-0 top-0 border-r shadow-sm" style={{ background: '#ffffff' }} />;
    }


    return (
        <>
            <Sider
                width={260}
                theme={isDarkMode ? "dark" : "light"}
                className="h-screen fixed left-0 top-0 border-r shadow-sm"
                style={{
                    background: isDarkMode ? '#141414' : '#ffffff',
                    height: '100vh',
                    position: 'fixed',
                    left: 0,
                    top: 0,
                    bottom: 0,
                    zIndex: 1000,
                    display: 'flex',
                    flexDirection: 'column',
                    borderRight: isDarkMode ? '1px solid #262626' : '1px solid #f0f0f0'
                }}
            >
                <div style={{ flex: 'none', padding: isDarkMode ? '24px 16px 12px' : '16px' }}>
                    <div
                        className={isDarkMode ? "py-2.5 px-4 rounded-xl text-[13px] font-bold text-center mb-4 transition-all" : "text-white py-1.5 px-4 rounded-full text-[12px] font-semibold text-center mb-3"}
                        style={{
                            backgroundColor: isDarkMode ? 'rgba(255, 255, 255, 0.05)' : primaryColor,
                            color: isDarkMode ? primaryColor : '#ffffff',
                            border: isDarkMode ? `1px solid ${primaryColor}40` : 'none',
                            letterSpacing: isDarkMode ? '0.5px' : 'normal'
                        }}
                    >
                        {tenantCode && tenantName ? `${tenantCode} - ${tenantName}` : (tenantName || t('company'))}
                    </div>

                    <Input
                        prefix={<SearchOutlined style={{ color: isDarkMode ? 'rgba(255,255,255,0.3)' : '#8c8c8c' }} />}
                        placeholder={t('searchText')}
                        value={searchValue}
                        onChange={(e) => setSearchValue(e.target.value)}
                        suffix={
                            isDarkMode ? (
                                <span style={{
                                    fontSize: '9px',
                                    color: 'rgba(255,255,255,0.3)',
                                    backgroundColor: 'rgba(255,255,255,0.03)',
                                    padding: '1px 5px',
                                    borderRadius: '4px',
                                    border: '1px solid rgba(255,255,255,0.08)'
                                }}>
                                    Ctrl K
                                </span>
                            ) : (
                                <span className="text-[10px] text-gray-400 bg-gray-50 px-1 rounded border">Ctrl K</span>
                            )
                        }
                        className={isDarkMode ? "modern-search-input" : "rounded-md"}
                        style={{
                            height: isDarkMode ? '40px' : '36px',
                            borderRadius: isDarkMode ? '10px' : undefined,
                            backgroundColor: isDarkMode ? 'rgba(255, 255, 255, 0.03)' : '#ffffff',
                            border: isDarkMode ? '1px solid rgba(255, 255, 255, 0.08)' : undefined,
                            color: isDarkMode ? 'rgba(255, 255, 255, 0.85)' : '#000000'
                        }}
                    />
                </div>

                {/* PHẦN MENU CHÍNH */}
                <div className={isDarkMode ? "flex-1 overflow-y-auto mt-2 px-3" : "flex-1 overflow-y-auto mt-2"}>
                    <ConfigProvider
                        theme={{
                            components: {
                                Menu: {
                                    itemBg: 'transparent',
                                    itemColor: isDarkMode ? 'rgba(255, 255, 255, 0.55)' : 'rgba(0, 0, 0, 0.85)',
                                    itemSelectedColor: isDarkMode ? '#ffffff' : primaryColor,
                                    itemSelectedBg: isDarkMode ? `${primaryColor}30` : `${primaryColor}10`,
                                    itemHoverColor: isDarkMode ? '#ffffff' : primaryColor,
                                    itemHoverBg: isDarkMode ? 'rgba(255, 255, 255, 0.05)' : 'rgba(0, 0, 0, 0.04)',
                                    itemBorderRadius: isDarkMode ? 10 : 4,
                                    itemMarginInline: isDarkMode ? 4 : 0,
                                    itemMarginBlock: isDarkMode ? 4 : 4,
                                },
                            },
                        }}
                    >
                        <Menu
                            mode="inline"
                            theme={isDarkMode ? "dark" : "light"}
                            selectedKeys={[pathname]}
                            openKeys={searchValue ? searchOpenKeys : openKeys}
                            onOpenChange={onOpenChange}
                            onClick={onClick}
                            items={items}
                            style={{
                                borderRight: 0,
                                backgroundColor: 'transparent'
                            }}
                            className="custom-sidebar-menu"
                        />
                    </ConfigProvider>
                </div>

                {/* Thẻ User Profile ở dưới cùng Sider */}
                <div
                    onClick={handleProfileClick}
                    style={{
                        flex: 'none',
                        padding: '16px',
                        borderTop: isDarkMode ? '1px solid #262626' : '1px solid #f0f0f0',
                        display: 'flex',
                        alignItems: 'center',
                        gap: '12px',
                        marginTop: 'auto',
                        cursor: 'pointer',
                        transition: 'all 0.3s ease'
                    }}
                    className={isDarkMode ? "hover:bg-zinc-800" : "hover:bg-gray-50"}
                >
                    <Avatar
                        style={{
                            backgroundColor: profileModalOpen ? '#fff' : primaryColor,
                            color: profileModalOpen ? primaryColor : '#fff',
                            border: profileModalOpen ? `2px solid ${primaryColor}` : 'none',
                            verticalAlign: 'middle',
                            fontWeight: 'bold',
                            flexShrink: 0,
                            transition: 'all 0.3s ease'
                        }}
                        size={38}
                    >
                        {userName ? userName.charAt(0).toUpperCase() : 'U'}
                    </Avatar>
                    <div style={{ overflow: 'hidden' }}>
                        <div style={{ color: isDarkMode ? 'rgba(255, 255, 255, 0.85)' : '#000000', fontWeight: '600', fontSize: '14px', whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>
                            {userName || 'User'}
                        </div>
                        <div style={{ color: isDarkMode ? 'rgba(255,255,255,0.45)' : '#8c8c8c', fontSize: '12px', whiteSpace: 'nowrap', textOverflow: 'ellipsis', overflow: 'hidden' }}>
                            {t('online', 'Trực tuyến')}
                        </div>
                    </div>
                </div>
            </Sider>

            {/* Modal cập nhật User Profile */}
            {profileModalOpen && (
                <FormModal
                    open={profileModalOpen}
                    editingUser={currentUserData}
                    onSuccess={() => { }}
                    onClose={() => setProfileModalOpen(false)}
                />
            )}
        </>
    );
}// Hàm bổ trợ để lấy tất cả keys nhằm bung hết menu khi search
const getAllKeys = (items: any[]): string[] => {
    let keys: string[] = [];
    items.forEach(item => {
        if (item.children) {
            keys.push(item.key);
            keys = [...keys, ...getAllKeys(item.children)];
        }
    });
    return keys;
};