'use client';

import { useEffect, useState } from 'react';
import { useRouter, usePathname } from 'next/navigation';
import { Spin } from 'antd';

export default function AuthWrapper({ children }: { children: React.ReactNode }) {
    const router = useRouter();
    const pathname = usePathname();
    const [isChecking, setIsChecking] = useState(true);

    useEffect(() => {
        const token = localStorage.getItem('access_token');
        const isLoginPage = pathname === '/login';

        if (!token && !isLoginPage) {
            // Trường hợp 1: Không có token và không ở trang login -> Về login
            router.push('/login');
        } else if (token && isLoginPage) {
            // Trường hợp 2: Có token mà lại vào trang login -> Vào products
            router.push('/products');
        } else {
            // Trường hợp 3: Hợp lệ
            setIsChecking(false);
        }
    }, [pathname, router]);

    // Trong lúc đang kiểm tra, hiển thị loading để tránh "giật" giao diện
    if (isChecking && pathname !== '/login') {
        return (
            <div className="flex h-screen w-full items-center justify-center">
                <Spin size="large" description="Đang kiểm tra quyền truy cập..." />
            </div>
        );
    }

    return <>{children}</>;
}